// Excluded project IDs
const excludedProjects = new Set([
  '6RjXPcqqq5p9cW6P',  // Prepping List
  '6XHpVGMXP2RVGHqr',  // MOVIES
  '6R4vjRGq8xHXR26h'   // Bucketlist
]);

const items = $input.all();

// Filter out excluded projects
const activeTasks = items.filter(item => {
  const projectId = item.json.projectId || item.json.project_id || '';
  return !excludedProjects.has(String(projectId));
});

// Group by project
const byProject = {};
for (const item of activeTasks) {
  const projectName = item.json.project?.name || item.json.projectName || 'Unknown Project';
  if (!byProject[projectName]) byProject[projectName] = [];
  byProject[projectName].push(item.json.content);
}

const totalStale = activeTasks.length;
const projectNames = Object.keys(byProject).sort();

// Build HTML email
let projectHtml = '';
for (const name of projectNames) {
  const tasks = byProject[name];
  const taskList = tasks.map(t => `<li style="padding:2px 0">${t}</li>`).join('');
  projectHtml += `
    <h3 style="color:#333;margin-bottom:4px">PROJECT: ${name} (${tasks.length} tasks)</h3>
    <ul style="margin-top:4px">${taskList}</ul>`;
}

if (totalStale === 0) {
  projectHtml = '<p style="color:#4caf50;font-weight:bold">No stale undated tasks found! Everything is dated or in reference projects.</p>';
}

const subject = `[Stale Tasks] ${totalStale} undated tasks need attention`;

const html = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">
  <h2 style="color:#333;border-bottom:2px solid #f59e0b;padding-bottom:8px">Stale Task Report</h2>
  ${projectHtml}
  <hr style="margin-top:20px;border:1px solid #eee">
  <p style="font-weight:bold">Total undated tasks in active projects: ${totalStale}</p>
  <p style="color:#666">Action: Add dates, move to reference projects, or delete</p>
  <p style="color:#999;font-size:12px;margin-top:20px">Generated by n8n Stale Task Detector workflow</p>
</div>`;

return [{ json: { subject, html, totalStale, hasStale: totalStale > 0 } }];
